async function initialisePageEditing(){if(!($(".component[name=Login]").length>0)){var n=new PageToolbar;await n.init();$("[contenteditable]").each(function(){new ContentEditor($(this),n.page).init()})}}$(initialisePageEditing);class ContentEditor{constructor(n,t){this.element=n;this.page=t;var i=t.Contents.filter(n=>n.Name===$(this.element).attr("name")&&n.CultureId===session.culture);i.length>0?this.pageContent=i[0]:(t.Contents.push({CultureId:session.culture,Name:$(this.element).attr("name"),Html:t.Contents.filter(n=>n.Name===$(this.element).attr("name")&&n.CultureId==="")[0].Html,PageId:t.Id}),this.pageContent=t.Contents.filter(n=>n.Name===$(this.element).attr("name")&&n.CultureId===session.culture)[0]);window.currentContentWidget=this}async init(){$(this.element).data("contentEditor",this);this.setupToolbars()}setupToolbars(){this.kendoEditor=$(this.element).kendoEditor({tools:["bold","italic","underline","undo","redo","justifyLeft","justifyCenter","justifyRight","insertUnorderedList","createLink","unlink","insertImage","tableWizard","createTable","addRowAbove","addRowBelow","addColumnLeft","addColumnRight","deleteRow","deleteColumn","mergeCellsHorizontally","mergeCellsVertically","splitCellHorizontally","splitCellVertically","tableAlignLeft","tableAlignCenter","tableAlignRight","formatting",{name:"fontName",items:[{text:"Andale Mono",value:'"Andale Mono"'},{text:"Arial",value:"Arial"},{text:"Arial Black",value:'"Arial Black"'},{text:"Book Antiqua",value:'"Book Antiqua"'},{text:"Comic Sans MS",value:'"Comic Sans MS"'},{text:"Courier New",value:'"Courier New"'},{text:"Georgia",value:"Georgia"},{text:"Helvetica",value:"Helvetica"},{text:"Impact",value:"Impact"},{text:"Symbol",value:"Symbol"},{text:"Tahoma",value:"Tahoma"},{text:"Terminal",value:"Terminal"},{text:"Times New Roman",value:'"Times New Roman"'},{text:"Trebuchet MS",value:'"Trebuchet MS"'},{text:"Verdana",value:"Verdana"},]},"fontSize","foreColor","backColor",{type:"button",name:"viewSource",template:'<button role="button" title="View Source" class="k-button k-tool" name="viewSource"><span class="k-icon k-i-file"><\/span><\/button>'}],change:()=>{this.pageContent.Html=this.kendoEditor.value()}}).data("kendoEditor");this.setupViewSourceButton()}setupViewSourceButton(){$("button[name=viewSource]",this.toolbarElement).click(n=>{n.preventDefault();var t=new Dialog({width:1e3,height:610,title:"View Source",template:`
                    <div class="editorContainer">
		                <textarea name="sourceEditor"></textarea>
                    </div>
                    <hr>
	                <div class="value">
		                <button name="close">Close</button>
	                </div>
                    <style scoped>
                         .editorContainer 				{ display: inline-block; width: 100%; height: 535px; margin-right: 10px; }
                         .editorContainer > textarea	{ width: 99%; height: 100%; }
                    </style>
                `});t.init(()=>{$("[name=sourceEditor]",t.element).val(this.kendoEditor.value());$("[name=sourceEditor]",t.element).on("keyup",()=>{this.kendoEditor.value($("[name=sourceEditor]",t.element).val()),this.pageContent.Html=$("[name=sourceEditor]",t.element).val()})})})}}class PageToolbar{async init(){await this.getPage();this.toolbarElement=$("body").prepend(`
            <div class="pageToolbar k-toolbar k-widget">
                <div class="tools-left">
                    <button name="selectPage"><span class="k-icon k-i-file" style="margin-right: 10px;"></span>Select Page</button>
                    <button name="newChildPage"><span class="k-icon k-i-plus"></span>New Child Page</button>
                    <button name="newRootPage"><span class="k-icon k-i-plus"></span>New Root Page</button>
                    <button name="deletePage"><span class="k-icon k-i-delete"></span>Delete Page</button>
                    <button name="pageProperties"><span class="k-icon k-i-page-properties"></span>Page Properties</button>
                </div>
                <div class="tools-right">
                    <div class="k-toolbar-item">
                        <label>Last Updated: </label>
                        <label name="lastUpdatedTime"></label>
                    </div>
                    <div class="k-toolbar-item">
                        <label>Culture: </label>
                        <input name="cultureDropdown" />
                    </div>
                    <div class="k-toolbar-item">
                        <button name="pageSave"><span class="k-icon k-i-save"></span>Save</button>
                    </div>
                </div>
            </div>
        `);$("[name=pageSave]",this.toolbarElement).click(n=>this.save(n));await this.setupCultureDropdown();$("[name=lastUpdatedTime]",this.toolbarElement).html(kendo.toString(new Date(this.page.LastUpdated),"yyyy-MM-dd hh:mm"));$("[name=selectPage]",this.toolbarElement).click(n=>this.selectPage(n));$("[name=newChildPage]",this.toolbarElement).click(n=>this.newPage(n,this.page.Id));$("[name=newRootPage]",this.toolbarElement).click(n=>this.newPage(n,null));$("[name=deletePage]",this.toolbarElement).click(n=>this.deletePage(n));$("[name=pageProperties]",this.toolbarElement).click(n=>this.pageProperties(n))}async getPage(){var n=window.location.pathname.substring(1);this.page=(await api.get("Core/Page?$filter=AppId eq "+session.app.Id+" and Path eq '"+n+"'&$expand=Contents")).value[0]}async save(n){n.preventDefault();this.page.Contents=this.page.Contents.filter(n=>n.Html.length>0||n.CultureId==="");await api.update("Core/Page("+this.page.Id+")",this.page).then(n=>{$("[name=lastUpdatedTime]",this.toolbarElement).html(kendo.toString(new Date(n.LastUpdated),"yyyy-MM-dd hh:mm")),notification.success("Saved"),this.page.Contents.filter(n=>n.CultureId===session.culture).length===0&&setQueryParameter("culture","")}).catch(n=>error(n))}async deletePage(n){n.preventDefault();await api.destroy("Core/Page("+this.page.Id+")").then(()=>{if(this.page.ParentId!=null){var n=await api.get("Core/Page("+this.page.ParentId+")");window.location.href=api.apiRoot.replaceAll("/Api/","/")+n.Path+"?edit=true"}else window.location.href=api.apiRoot.replaceAll("/Api/","/?edit=true")}).catch(n=>error(n))}async newPage(n,t){n.preventDefault();var i=new EditorDialog({title:"New Page",fields:[{field:"Name",title:"Name"}],data:{Name:"",ParentId:t,AppId:this.page.AppId,ShowOnMenus:!1,Path:null,Layout:"Default",Order:0,Contents:[],PageInfo:[]},confirm:"Create"});i.events.confirm=async function(){var n=i.data.toJSON();n.Contents.push({CultureId:"",Name:"body",Html:""});n.PageInfo.push({CultureId:"",Title:n.Name});await api.post("Core/Page",n).then(n=>{notification.success("Child page created"),window.location.href=api.apiRoot.replaceAll("/Api/","/")+n.Path+"?edit=true",i.events.close()}).catch(n=>error(n))};i.init()}async selectPage(n){n.preventDefault();var t=new Dialog({width:400,height:600,title:"Select Page"});t.init(()=>{var n=await loadComponent(t.element,"CMS");await n.init(session.app,$(".component[name=CMS]",t.element),n=>{window.location.href=window.location.href.replaceAll(this.page.Path,n.Path)})})}async setupCultureDropdown(){var n=(await api.get("Core/Culture?$filter=Apps/any(a: a/AppId eq "+session.app.Id+") or Id eq ''")).value;for(let t=0;t<n.length;t++)n[t].InPage=this.page.Contents.filter(i=>i.CultureId===n[t].Id).length>0;$("[name=cultureDropdown]").kendoDropDownList({dataSource:n,dataTextField:"Name",dataValueField:"Id",valueTemplate:"#=(InPage) ? '<span class=\"k-icon k-i-check\"><\/span>' : '<span class=\"k-icon k-i-x\"><\/span>'# #=Name#",template:"#=(InPage) ? '<span class=\"k-icon k-i-check\"><\/span>' : '<span class=\"k-icon k-i-x\"><\/span>'# #=Name#",change:function(){setQueryParameter("culture",this.value())}}).data("kendoDropDownList").value(session.culture)}async pageProperties(n){n.preventDefault();var t=new Dialog({title:"Page Properties: "+this.page.Path,width:900,height:250});t.init(()=>{var n=await loadComponent(t.element,"PageProperties");n.init(session.app,$(".component[name=PageProperties]",$(t.element)),this.page,n=>{this.save(n)})})}}